diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..b1da6a395902 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2229,6 +2229,62 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   if (!MinMax)
     return nullptr;

+  // If both operands of sub are the same min/max intrinsic, try to fold to
+  // a select of constants. For example:
+  // sub(smin(X+C, Y), smin(X, Y)) --> select(icmp slt X, Y), C, 0
+  // sub(smax(X+C, Y), smax(X, Y)) --> select(icmp sgt X, Y), C, 0
+  if (auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0)) {
+    if (MinMax0->getIntrinsicID() == MinMax->getIntrinsicID() &&
+        (MinMax0->hasOneUse() || MinMax->hasOneUse())) {
+      Intrinsic::ID ID = MinMax->getIntrinsicID();
+      bool IsSigned = MinMax->isSigned();
+      // Determine the comparison predicate based on min/max kind.
+      ICmpInst::Predicate Pred;
+      switch (ID) {
+      case Intrinsic::smin: Pred = ICmpInst::ICMP_SLT; break;
+      case Intrinsic::smax: Pred = ICmpInst::ICMP_SGT; break;
+      case Intrinsic::umin: Pred = ICmpInst::ICMP_ULT; break;
+      case Intrinsic::umax: Pred = ICmpInst::ICMP_UGT; break;
+      default: llvm_unreachable("unexpected minmax intrinsic");
+      }
+
+      // Try all four operand orderings to find the shared operand and the
+      // constant offset. We accept either an add with appropriate nowrap
+      // flags, or an "or disjoint" (which is equivalent to add nuw nsw).
+      auto TryFold = [&](Value *A0, Value *B0, Value *A1, Value *B1) -> Instruction * {
+        // Look for B0 == B1 (shared) and A0 = A1 + C with nowrap.
+        if (B0 != B1)
+          return nullptr;
+        const APInt *C;
+        // Match A0 = A1 + C (with appropriate nowrap or disjoint or).
+        if (match(A0, m_OneUse(
+                IsSigned ? m_NSWAddLike(m_Specific(A1), m_APInt(C))
+                         : m_NUWAddLike(m_Specific(A1), m_APInt(C))))) {
+          Value *Cmp = Builder.CreateICmp(Pred, A1, B1);
+          return SelectInst::Create(Cmp, ConstantInt::get(Ty, *C),
+                                    ConstantInt::get(Ty, 0));
+        }
+        // Match A1 = A0 + C (with appropriate nowrap or disjoint or).
+        if (match(A1, m_OneUse(
+                IsSigned ? m_NSWAddLike(m_Specific(A0), m_APInt(C))
+                         : m_NUWAddLike(m_Specific(A0), m_APInt(C))))) {
+          Value *Cmp = Builder.CreateICmp(Pred, A0, B1);
+          return SelectInst::Create(Cmp, ConstantInt::get(Ty, 0),
+                                    ConstantInt::get(Ty, *C));
+        }
+        return nullptr;
+      };
+
+      Value *A0 = MinMax0->getLHS(), *B0 = MinMax0->getRHS();
+      Value *A1 = MinMax->getLHS(), *B1 = MinMax->getRHS();
+      if (Instruction *R = TryFold(A0, B0, A1, B1)) return R;
+      if (Instruction *R = TryFold(A0, B0, B1, A1)) return R;
+      if (Instruction *R = TryFold(B0, A0, A1, B1)) return R;
+      if (Instruction *R = TryFold(B0, A0, B1, A1)) return R;
+    }
+    return nullptr;
+  }
+
   // sub(add(X,Y), s/umin(X,Y)) --> s/umax(X,Y)
   // sub(add(X,Y), s/umax(X,Y)) --> s/umin(X,Y)
   Value *X = MinMax->getLHS();

